  ('fire-eq-tech-moex-01741', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，有關緊急廣播設備的規定，下列敘述何者錯誤？', '["緊急廣播設備之音響警報應以語音方式播放", "緊急廣播設備與其他設備共用者，在火災時應能遮斷緊急廣播設備以外之廣播", "廣播區域超過50平方公尺100平方公尺以下時，設Ｌ級或Ｍ級揚聲器", "導線間及導線對大地間之絕緣電阻值，以直流250伏特額定之絕緣電阻計測定，對地電壓超過150伏 特者，在0.1ＭΩ以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01742', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某一地下建築物總樓地板面積超過500平方公尺未達1,000平方公尺，不符合免設條件，依據各類場所消 防安全設備設置標準，下列那一種消防安全設備依法應設置？', '["排煙設備", "緊急電源插座", "無線電通信輔助設備", "瓦斯漏氣火警自動警報設備"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01743', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，出口標示燈應設於下列出入口上方或其緊鄰之有效引導避難處， 下列敘述何者錯誤？', '["通往戶外之出入口；設有排煙室者，為該室之出入口", "通往第一款及第二款出入口，走廊或通道上所設跨防火區劃之出入口", "通往直通樓梯之出入口；設有排煙室者，為該室之出入口", "通往前二款出入口，由室內往走廊或通道之出入口"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01744', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，下列那一場所使用之樓層，主要構造為防火構造且設有二座以上 安全梯，且該樓層各部分均有二個以上不同避難逃生路徑能通達安全梯，符合避難器具免設之規定？', '["金融機構", "活動中心", "室內溜冰場", "電影攝影場"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01745', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，有關緩降機設置及其支固器具之裝置規定，下列敘述何者錯誤？', '["緩降機之設置，在下降時，所使用繩子應避免與使用場所牆面或突出物接觸", "支固器具設在使用場所之磚牆或其他構造上較堅固及容易裝設場所", "緩降機所使用繩子之長度，以其裝置位置至地面或其他下降地點之等距離長度為準", "支固器具以螺栓、熔接或其他堅固方法裝置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01746', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，有關緊急照明燈之構造規定，下列敘述何者錯誤？', '["白熾燈為雙重繞燈絲燈泡，其燈座為瓷製或與瓷質同等以上之耐熱絕緣材料製成者", "日光燈為瞬時起動型，其燈座為耐熱絕緣樹脂製成者", "放電燈之安定器，裝設於一般性外箱", "水銀燈為高壓瞬時點燈型，其燈座為瓷製或與瓷質同等以上之耐熱絕緣材料製成者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01747', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，特別安全梯或緊急昇降機間排煙室之排煙設備設置於直接面向戶 外之窗戶時，下列規定及敘述何者錯誤？', '["在排煙時窗戶與煙接觸部分使用不燃材料", "窗戶有效開口面積位於天花板高度二分之一以上之範圍內", "窗戶之有效開口面積在2平方公尺以上。但特別安全梯排煙室與緊急昇降機間兼用時，應在3平方公 尺以上", "平時關閉之窗戶設手動開關裝置，其操作部分設於距離樓地板180公分之位置，並標示簡易之操作方式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01748', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，有關緊急供電系統之配線除依屋內線路裝置規則外，下列規定及 敘述何者錯誤？', '["電源回路之配線，施予耐熱保護", "標示燈回路及控制回路之配線，施予耐熱保護", "電氣配線應設專用回路，不得與一般電路相接，且開關有消防安全設備別之明顯標示", "緊急用電源回路及操作回路，使用600伏特耐熱絕緣電線，或同等耐熱效果以上之電線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01749', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據火警探測器認可基準規定，有關火警自動警報設備所使用火警探測器之構造，下列敘述何者錯誤？', '["不得因氣流方向改變而影響探測功能", "探測器的底座視為探測器的一部位，且與本體連結試驗100次後，內部接觸彈片不得發生異狀及功能 失效", "應有排除水分侵入之功能", "探測器之接點不得露出在外"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
